// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ShadowOTC {
    enum DealStatus { Open, Accepted, Completed, Failed }

    struct Deal {
        address buyer;
        address seller;
        uint256 amount;
        string intent;
        DealStatus status;
    }

    uint256 public dealCounter;
    mapping(uint256 => Deal) public deals;

    event DealCreated(uint256 indexed dealId, address buyer, string intent, uint256 amount);
    event DealAccepted(uint256 indexed dealId, address seller);
    event DealExecuted(uint256 indexed dealId, bool success);

    function createDeal(string calldata intent) external payable returns (uint256) {
        require(msg.value > 0, "Must lock funds");
        uint256 dealId = dealCounter++;
        deals[dealId] = Deal({
            buyer: msg.sender,
            seller: address(0),
            amount: msg.value,
            intent: intent,
            status: DealStatus.Open
        });
        emit DealCreated(dealId, msg.sender, intent, msg.value);
        return dealId;
    }

    function acceptDeal(uint256 dealId) external {
        Deal storage deal = deals[dealId];
        require(deal.status == DealStatus.Open, "Deal not open");
        require(deal.buyer != msg.sender, "Buyer cannot be seller");
        deal.seller = msg.sender;
        deal.status = DealStatus.Accepted;
        emit DealAccepted(dealId, msg.sender);
    }

    function executeDeal(uint256 dealId, bool success) external {
        Deal storage deal = deals[dealId];
        require(deal.status == DealStatus.Accepted, "Deal not accepted");
        if (success) {
            deal.status = DealStatus.Completed;
            payable(deal.seller).transfer(deal.amount);
        } else {
            deal.status = DealStatus.Failed;
            payable(deal.buyer).transfer(deal.amount);
        }
        emit DealExecuted(dealId, success);
    }

    function getDeal(uint256 dealId) external view returns (Deal memory) {
        return deals[dealId];
    }
}

